2	import jwt, { SignOptions } from 'jsonwebtoken';
3	import request from 'supertest';
4	import { createApp } from '../../src/app';
5	import { loadConfig } from '../../src/config/env';
6	import { AppDataSource } from '../../src/data-source';
7	import { User } from '../../src/entities/user.entity';
8	import {
9	  FinancialRecord,
10	  FinancialRecordType,
11	  FinancialRecordTypeCategory,
12	} from '../../src/entities/financial-record.entity';
13	
14	const PASSWORD_HASH_ROUNDS = 4;
15	
16	interface CreateUserOverrides {
17	  name?: string;
18	  email?: string;
19	  password?: string;
20	}
21	
22	const createUser = async (overrides: CreateUserOverrides = {}): Promise<User> => {
23	  const repo = AppDataSource.getRepository(User);
24	  const user = repo.create({
25	    name: overrides.name ?? 'Ada Lovelace',
26	    email: overrides.email ?? 'ada@example.com',
27	    password:
28	      overrides.password ??
29	      (await bcrypt.hash('correct horse battery staple', PASSWORD_HASH_ROUNDS)),
30	  });
31	  return repo.save(user);
32	};
33	
34	const tokenForUser = (user: Pick<User, 'id' | 'email'>): string => {
35	  const { jwtSecret } = loadConfig();
36	  const options: SignOptions = { expiresIn: '1h' };
37	  return jwt.sign({ userId: user.id, email: user.email }, jwtSecret, options);
38	};
39	
40	interface RecordSeed {
41	  amount: number;
42	  type: FinancialRecordType;
43	  typeCategory?: FinancialRecordTypeCategory | null;
44	  description?: string;
45	  transactionDate: Date;
46	}
47	
48	const seedRecords = async (userId: string, seeds: RecordSeed[]): Promise<void> => {
49	  const repo = AppDataSource.getRepository(FinancialRecord);
50	  await repo.save(
51	    seeds.map((seed) =>
52	      repo.create({
53	        userId,
54	        amount: seed.amount.toFixed(2),
55	        type: seed.type,
56	        typeCategory: seed.typeCategory ?? null,
57	        description: seed.description ?? `${seed.type} record`,
58	        transactionDate: seed.transactionDate,
59	      }),
60	    ),
61	  );
62	};
63	
64	const utc = (year: number, monthIndex: number, day: number, hour = 12): Date =>
65	  new Date(Date.UTC(year, monthIndex, day, hour, 0, 0, 0));
66	
67	describe('GET /financial/dashboard (integration)', () => {
68	  beforeAll(async () => {
69	    await AppDataSource.initialize();
70	    await AppDataSource.runMigrations();
71	  });
72	
73	  afterAll(async () => {
74	    await AppDataSource.destroy();
75	  });
76	
77	  beforeEach(async () => {
78	    await AppDataSource.query(
79	      'TRUNCATE TABLE "financial_records", "users" RESTART IDENTITY CASCADE',
80	    );
81	  });
82	
83	  describe('authentication', () => {
84	    it('returns 401 when no Authorization header is sent', async () => {
85	      const response = await request(createApp()).get('/financial/dashboard');
86	      expect(response.status).toBe(401);
87	      expect(response.body).toEqual({
88	        error: 'Missing or malformed authorization header',
89	      });
90	    });
91	
92	    it('returns 401 when the Authorization header is malformed', async () => {
93	      const response = await request(createApp())
94	        .get('/financial/dashboard')
95	        .set('Authorization', 'NotBearer abc');
96	      expect(response.status).toBe(401);
97	    });
98	
99	    it('returns 401 when the JWT signature is invalid', async () => {
100	      const response = await request(createApp())
101	        .get('/financial/dashboard')
102	        .set('Authorization', 'Bearer not-a-real-token');
103	      expect(response.status).toBe(401);
104	      expect(response.body).toEqual({ error: 'Invalid token' });
105	    });
106	
107	    it('returns 401 when the JWT has expired', async () => {
108	      const user = await createUser();
109	      const { jwtSecret } = loadConfig();
110	      const expired = jwt.sign({ userId: user.id, email: user.email }, jwtSecret, {
111	        expiresIn: '-1s',
112	      });
113	      const response = await request(createApp())
114	        .get('/financial/dashboard')
115	        .set('Authorization', `Bearer ${expired}`);
116	      expect(response.status).toBe(401);
117	      expect(response.body).toEqual({ error: 'Token has expired' });
118	    });
119	  });
120	
121	  describe('query parameter validation', () => {
122	    it('rejects a non-2-digit month', async () => {
123	      const user = await createUser();
124	      const token = tokenForUser(user);
125	
126	      const response = await request(createApp())
127	        .get('/financial/dashboard?month=3')
128	        .set('Authorization', `Bearer ${token}`);
129	
130	      expect(response.status).toBe(400);
131	      expect(response.body.error).toBe('ValidationError');
132	    });
133	
