export const calculateDti = (totalIncome: number, totalExpenditure: number): number | null => {
  if (totalIncome <= 0) {
    return null;
  }
  return totalExpenditure / totalIncome;
};

// Progress is a 0–100 score derived from DTI: lower DTI → more headroom →
// higher progress. (1 - DTI) * 100 clamps naturally onto the colour bands —
// 65–100 green, 30–64 amber, 0–29 red — matching the thresholds in the spec.
export const calculateProgress = (totalIncome: number, totalExpenditure: number): number => {
  const dti = calculateDti(totalIncome, totalExpenditure);
  if (dti === null) {
    return 0;
  }
  const raw = (1 - dti) * 100;
  return Math.max(0, Math.min(100, Math.round(raw)));
};

