describe('financial health colour thresholds', () => {
  it.each([
    { totalIncome: 1000, totalOutgoing: 0, expectedProgress: 100 },
    { totalIncome: 1000, totalOutgoing: 350, expectedProgress: 65 }, // green boundary
    { totalIncome: 1000, totalOutgoing: 360, expectedProgress: 64 }, // amber boundary
    { totalIncome: 1000, totalOutgoing: 700, expectedProgress: 30 }, // amber boundary
    { totalIncome: 1000, totalOutgoing: 710, expectedProgress: 29 }, // red
    { totalIncome: 1000, totalOutgoing: 1500, expectedProgress: 0 }, // DTI > 100%
  ])(
    'computes progress=$expectedProgress for income=$totalIncome / outgoing=$totalOutgoing',
    async ({ totalIncome, totalOutgoing, expectedProgress }) => {
      const user = await createUser({ email: `user-${totalOutgoing}@example.com` });
      const token = tokenForUser(user);
      const currentYear = new Date().getUTCFullYear();
      const targetMonthIndex = 5; // June

      await seedRecords(user.id, [
        {
          amount: totalIncome,
          type: 'income',
          transactionDate: utc(currentYear, targetMonthIndex, 10),
        },
        {
          amount: totalOutgoing,
          type: 'outgoing',
          transactionDate: utc(currentYear, targetMonthIndex, 20),
        },
      ]);

      const response = await request(createApp())
        .get('/financial/dashboard?month=06')
        .set('Authorization', `Bearer ${token}`);

      expect(response.status).toBe(200);
      const targetEntry = response.body.overTimeProgress[0];
      expect(targetEntry.progress).toBe(expectedProgress);
      expect(targetEntry.disposable_income).toBe(totalIncome - totalOutgoing);
    },
  );
});

